"use client";

import { create } from "zustand";

import type { GameState } from "@engine/state";

export type ContextPanelMode = "inspect" | "inventory" | "quest" | "dialogue";

export type UiSlice = {
  readonly contextPanelMode: ContextPanelMode;
  readonly diaryOpen: boolean;
  readonly artifactOpen: boolean;
};

export type GameStore = {
  readonly gameState: GameState | null;
  readonly ui: UiSlice;
  readonly setGameState: (state: GameState) => void;
  readonly patchUi: (patch: Partial<UiSlice>) => void;
};

const defaultUi: UiSlice = {
  contextPanelMode: "inspect",
  diaryOpen: false,
  artifactOpen: false,
};

export const useGameStore = create<GameStore>((set) => ({
  gameState: null,
  ui: defaultUi,
  setGameState: (gameState) => set({ gameState }),
  patchUi: (patch) =>
    set((current) => ({
      ui: { ...current.ui, ...patch },
    })),
}));

import { createInitialState, type GameState } from "@engine/state";

export const DEV_FIXTURE_SEED = "phase-48-dev-fixture";

export const createDevFixtureState = (): GameState =>
  createInitialState(DEV_FIXTURE_SEED);

"use client";

import { useGameStore } from "@/store/game-store";
import { GridRegion } from "@/components/grid";

const regionClass =
  "rounded border border-gg-border bg-gg-surface text-gg-muted flex items-center justify-center text-sm uppercase tracking-wide";
const gridRegionClass = "min-h-0";

export function GameShell() {
  const gameState = useGameStore((state) => state.gameState);
  const ui = useGameStore((state) => state.ui);

  return (
    <main className="grid h-screen grid-rows-[minmax(0,1fr)_7rem] gap-2 overflow-hidden p-3">
      <div className="grid min-h-0 grid-cols-[minmax(0,1fr)_minmax(18rem,24rem)] gap-2">
        <GridRegion className={gridRegionClass} state={gameState} />

        <div className="grid min-h-0 grid-rows-[minmax(7rem,auto)_minmax(0,1fr)] gap-2">
          <section className={regionClass} aria-label="HUD">
            HUD
            {gameState !== null ? (
              <span className="ml-2 text-gg-text">
                HP {gameState.player.hp.current}/{gameState.player.hp.max}
              </span>
            ) : null}
          </section>

          <section className={regionClass} aria-label="Context panel">
            Context · {ui.contextPanelMode}
          </section>
        </div>
      </div>

      <section className={regionClass} aria-label="Message log">
        Message log
        {gameState !== null && gameState.log.length > 0 ? (
          <span className="ml-2 truncate text-gg-text">
            {gameState.log.length} events
          </span>
        ) : null}
      </section>
    </main>
  );
}

import { fileURLToPath } from "node:url";

import { defineConfig } from "vitest/config";

const root = fileURLToPath(new URL("../../../", import.meta.url));

export default defineConfig({
  define: {
    "process.env.NODE_ENV": JSON.stringify("test"),
  },
  oxc: {
    jsx: {
      importSource: "react",
      runtime: "automatic",
    },
  },
  resolve: {
    alias: [
      { find: "@", replacement: `${root}app` },
      {
        find: /^@engine\/map$/,
        replacement: `${root}src/engine/map/index.ts`,
      },
      {
        find: /^@engine\/render$/,
        replacement: `${root}src/engine/render/index.ts`,
      },
      {
        find: /^@engine\/render\/grid$/,
        replacement: `${root}src/engine/render/grid.ts`,
      },
      {
        find: /^@engine\/state$/,
        replacement: `${root}src/engine/state/index.ts`,
      },
    ],
  },
  test: {
    environment: "node",
    include: ["app/components/grid/**/*.test.ts"],
  },
});

"use client";

import {
  memo,
  useEffect,
  useMemo,
  useRef,
  useState,
  type CSSProperties,
} from "react";

import { useGameStore } from "@/store/game-store";
import type { GameState } from "@engine/state";

import {
  GRID_FIXTURE_STORIES,
  createMidActionGridFixtureState,
} from "./fixtures";
import styles from "./GameGrid.module.css";
import {
  createGridViewModel,
  hasRenderableGrid,
  type GridCellView,
  type GridLayer,
  type GridRenderCursor,
  type GridShape,
  type GridViewModel,
} from "./model";

type GameGridProps = {
  readonly state: GameState | null;
  readonly glyphSizeRem?: number;
};

type GridRegionProps = GameGridProps & {
  readonly className?: string;
};

export function GridRegion({
  state,
  glyphSizeRem,
  className,
}: GridRegionProps) {
  const setGameState = useGameStore((store) => store.setGameState);
  const devFixtureMode = useLocalDevFixtureMode();
  const needsDevFixture =
    devFixtureMode && (state === null || !hasRenderableGrid(state));

  useEffect(() => {
    if (needsDevFixture) {
      setGameState(createMidActionGridFixtureState());
    }
  }, [needsDevFixture, setGameState]);

  return (
    <section
      className={[styles.region, className].filter(Boolean).join(" ")}
      aria-label="The grid"
    >
      <GameGrid state={state} glyphSizeRem={glyphSizeRem} />
      {devFixtureMode ? <GridFixtureControls /> : null}
    </section>
  );
}

export function GameGrid({ state, glyphSizeRem }: GameGridProps) {
  const cursorRef = useRef<GridRenderCursor | undefined>(undefined);
  const model = useMemo(() => {
    if (state === null) {
      return null;
    }

    const nextModel = createGridViewModel(state, cursorRef.current);
    cursorRef.current = nextModel.cursor;

    return nextModel;
  }, [state]);

  if (model === null || model.width === 0 || model.height === 0) {
    return (
      <div className={styles.stage}>
        <div className={styles.empty}>No floor grid</div>
      </div>
    );
  }

  return <GridFrame model={model} glyphSizeRem={glyphSizeRem} />;
}

export function GridFrame({ model, glyphSizeRem }: {
  readonly model: GridViewModel;
  readonly glyphSizeRem?: number;
}) {
  const style = {
    gridTemplateColumns: `repeat(${model.width}, var(--gg-grid-cell-size))`,
    ...(glyphSizeRem === undefined
      ? {}
      : { "--gg-grid-glyph-size": `${glyphSizeRem}rem` }),
  } as CSSProperties;

  return (
    <div className={styles.stage}>
      <div
        className={styles.grid}
        role="grid"
        aria-rowcount={model.height}
        aria-colcount={model.width}
        data-width={model.width}
        data-height={model.height}
        style={style}
      >
        {model.rows.map((row, rowIndex) => (
          <div
            className={styles.row}
            role="row"
            aria-rowindex={rowIndex + 1}
            key={rowIndex}
          >
            {row.map((cell) => (
              <GridCell cell={cell} key={cell.key} />
            ))}
          </div>
        ))}
      </div>
    </div>
  );
}

const GridCell = memo(
  function GridCell({ cell }: { readonly cell: GridCellView }) {
    const className = [
      styles.cell,
      styles[cell.fog],
      layerClass(cell.layer),
      shapeClass(cell.shape),
      cell.hitFlash ? styles.hitFlash : "",
      cell.motion === null ? "" : styles.moveArrive,
    ]
      .filter(Boolean)
      .join(" ");
    const style = (
      cell.motion === null
        ? undefined
        : {
            "--gg-move-x": String(cell.motion.dx),
            "--gg-move-y": String(cell.motion.dy),
          }
    ) as CSSProperties | undefined;

    return (
      <div
        className={className}
        role="gridcell"
        aria-colindex={cell.x + 1}
        aria-label={`${cell.x},${cell.y} ${cell.label}`}
        title={`${cell.x},${cell.y} ${cell.label}`}
        data-x={cell.x}
        data-y={cell.y}
        data-glyph={cell.glyph}
        data-fog={cell.fog}
        data-layer={cell.layer}
        data-label={cell.label}
        data-shape={cell.shape}
        data-hit-flash={cell.hitFlash ? "true" : "false"}
        data-motion={cell.motion === null ? "none" : "arrive"}
        style={style}
      >
        <span className={styles.glyph} aria-hidden="true">
          {cell.glyph === " " ? "\u00a0" : cell.glyph}
        </span>
        {cell.badge.length > 0 ? (
          <span className={styles.badge} aria-hidden="true">
            {cell.badge}
          </span>
        ) : null}
        {cell.pulses.map((pulse) => (
          <span
            className={[
              styles.pulse,
              pulse.kind === "damage"
                ? styles.damagePulse
                : styles.healPulse,
            ].join(" ")}
            data-pulse-kind={pulse.kind}
            key={pulse.id}
            aria-hidden="true"
          >
            {pulse.text}
          </span>
        ))}
      </div>
    );
  },
  (previous, next) => previous.cell.renderKey === next.cell.renderKey,
);

function GridFixtureControls() {
  const setGameState = useGameStore((state) => state.setGameState);

  return (
    <div className={styles.fixtureBar} aria-label="Grid fixtures">
      {GRID_FIXTURE_STORIES.map((fixture) => (
        <button
          className={styles.fixtureButton}
          key={fixture.id}
          type="button"
          onClick={() => setGameState(fixture.createState())}
        >
          {fixture.label}
        </button>
      ))}
    </div>
  );
}

const layerClass = (layer: GridLayer): string => {
  switch (layer) {
    case "player":
      return cssClass(styles.player);
    case "enemy":
      return cssClass(styles.enemy);
    case "npc":
      return cssClass(styles.npc);
    case "item":
      return cssClass(styles.item);
    case "trap":
      return cssClass(styles.trap);
    case "terrain":
      return cssClass(styles.terrain);
    case "empty":
      return cssClass(styles.emptyLayer);
  }
};

const shapeClass = (shape: GridShape): string => {
  switch (shape) {
    case "circle":
      return `${cssClass(styles.shape)} ${cssClass(styles.shapeCircle)}`;
    case "diamond":
      return `${cssClass(styles.shape)} ${cssClass(styles.shapeDiamond)}`;
    case "square":
      return `${cssClass(styles.shape)} ${cssClass(styles.shapeSquare)}`;
    case "dot":
      return `${cssClass(styles.shape)} ${cssClass(styles.shapeDot)}`;
    case "triangle":
      return `${cssClass(styles.shape)} ${cssClass(styles.shapeTriangle)}`;
    case "none":
      return "";
  }
};

const cssClass = (className: string | undefined): string => className ?? "";

const useLocalDevFixtureMode = (): boolean => {
  const [enabled, setEnabled] = useState(false);

  useEffect(() => {
    setEnabled(isLocalDevBrowser());
  }, []);

import { createElement } from "react";
import { renderToStaticMarkup } from "react-dom/server";
import { describe, expect, it } from "vitest";

import { GridFrame } from "./GameGrid";
import {
  createFogMixGridFixtureState,
  createLargestBandFixtureState,
  createMidActionGridFixtureState,
  createPrecedenceFixtureState,
  withMovedPlayer,
} from "./fixtures";
import {
  createGridViewModel,
  type GridCellView,
  type GridViewModel,
} from "./model";
import type { GameState } from "@engine/state";

describe("GameGrid", () => {
  it("renders one cell per tile with visible, remembered, and unseen fog states", () => {
    const model = createGridViewModel(createFogMixGridFixtureState());
    const markup = renderGrid(model);

    expect(model.width).toBe(5);
    expect(model.height).toBe(3);
    expect(gridCellCount(markup)).toBe(15);
    expect(cellAt(model, 1, 1)).toMatchObject({
      glyph: "@",
      fog: "visible",
      layer: "player",
      badge: "YOU",
      shape: "circle",
    });
    expect(cellAt(model, 0, 0)).toMatchObject({
      glyph: ":",
      fog: "remembered",
      layer: "terrain",
    });
    expect(cellAt(model, 2, 1)).toMatchObject({
      glyph: ",",
      fog: "remembered",
      layer: "terrain",
    });
    expect(cellAt(model, 4, 0)).toMatchObject({
      glyph: " ",
      fog: "unseen",
      layer: "empty",
    });
    expect(markup).toContain('data-fog="remembered"');
    expect(markup).toContain('data-fog="unseen"');
  });

  it("matches engine layering precedence for player, enemy, npc, item, and revealed trap cells", () => {
    const model = createGridViewModel(createPrecedenceFixtureState());

    expect(rowGlyphs(model)).toBe("@eN?^");
    expect(cellAt(model, 0, 0)).toMatchObject({
      layer: "player",
      badge: "YOU",
      shape: "circle",
    });
    expect(cellAt(model, 1, 0)).toMatchObject({
      layer: "enemy",
      badge: "FOE",
      shape: "diamond",
    });
    expect(cellAt(model, 2, 0)).toMatchObject({
      layer: "npc",
      badge: "NPC",
      shape: "square",
    });
    expect(cellAt(model, 3, 0)).toMatchObject({
      layer: "item",
      badge: "ITM",
      shape: "dot",
    });
    expect(cellAt(model, 4, 0)).toMatchObject({
      layer: "trap",
      badge: "TRP",
      shape: "triangle",
    });
  });

  it("renders damage and heal pulses only for log events since the previous render", () => {
    const base = createMidActionGridFixtureState();
    const before = createGridViewModel(base);
    const after = createGridViewModel(withPulseEvents(base), before.cursor);
    const enemyCell = cellAt(after, 3, 1);
    const playerCell = cellAt(after, 1, 1);
    const markup = renderGrid(after);

    expect(enemyCell.hitFlash).toBe(true);
    expect(enemyCell.pulses).toEqual([
      expect.objectContaining({
        kind: "damage",
        text: "-3",
      }),
    ]);
    expect(playerCell.hitFlash).toBe(false);
    expect(playerCell.pulses).toEqual([
      expect.objectContaining({
        kind: "heal",
        text: "+2",
      }),
    ]);
    expect(markup).toContain('data-hit-flash="true"');
    expect(markup).toContain('data-pulse-kind="damage"');
    expect(markup).toContain('data-pulse-kind="heal"');
  });

  it("keeps largest-band Node static render work inside the per-update budget", () => {
    /*
     * This measures view-model construction plus React static markup rendering in
     * Vitest's Node process for 40x24 over 100 updates. It does not include browser
     * style, layout, paint, or input dispatch; the true UX <16ms claim still needs
     * a browser verifier pass.
     */
    const updateCount = 100;
    const budgetMsPerUpdate = 16;
    let state = createLargestBandFixtureState();
    let cursor = createGridViewModel(state).cursor;
    const startedAt = performance.now();

    for (let index = 0; index < updateCount; index += 1) {
      state = withMovedPlayer(
        state,
        {
          x: 1 + (index % 38),
          y: 1 + (Math.floor(index / 38) % 22),
        },
        index + 1,
      );
      const model = createGridViewModel(state, cursor);
      renderGrid(model);
      cursor = model.cursor;
    }

    const elapsedMs = performance.now() - startedAt;
    const averageMs = elapsedMs / updateCount;

    console.info(
      `largest-band static render: ${averageMs.toFixed(2)}ms/update (${elapsedMs.toFixed(1)}ms/${updateCount})`,
    );
    expect(averageMs).toBeLessThan(budgetMsPerUpdate);
  });
});

const renderGrid = (model: GridViewModel): string =>
  renderToStaticMarkup(createElement(GridFrame, { model }));

const gridCellCount = (markup: string): number =>
  markup.match(/role="gridcell"/g)?.length ?? 0;

const cellAt = (
  model: GridViewModel,
  x: number,
  y: number,
): GridCellView => {
  const cell = model.cells.find((entry) => entry.x === x && entry.y === y);

  if (cell === undefined) {
    throw new Error(`missing cell ${x},${y}`);
  }

  return cell;
};

const rowGlyphs = (model: GridViewModel): string =>
  model.rows[0]?.map((cell) => cell.glyph).join("") ?? "";

const withPulseEvents = (state: GameState): GameState => ({
  ...state,
  player: {
    ...state.player,
    hp: {
      ...state.player.hp,
      current: state.player.hp.current + 2,
    },
  },
  entities: {
    ...state.entities,
    "enemy#1": {
      ...state.entities["enemy#1"],
      currentHP: 3,
    } as NonNullable<typeof state.entities["enemy#1"]>,
  },
  log: [
    ...state.log,
    {
      turn: state.run.turn + 1,
      type: "attack_hit",
      data: {
        actorId: "player",
        defenderId: "enemy#1",
        attackerAttack: 5,
        defenderDefense: 1,
        baseDamage: 4,
        damage: 3,
        hitRoll: 8,
        hitChancePercent: 95,
        varianceMultiplier: 1,
        defenderHpBefore: 6,
        defenderHpAfter: 3,
      },
    } as GameState["log"][number],
    {
      turn: state.run.turn + 1,
      type: "status_tick",
      data: {
        entityId: "player",
        status: "regen",
        hpDelta: 2,
      },
    } as GameState["log"][number],
  ],
});

