  display: grid;
  min-height: 0;
  overflow: hidden;
  border: 1px solid var(--gg-border);
  border-radius: 8px;
  background: #0d1117;
}

.stage {
  display: grid;
  min-width: 0;
  min-height: 0;
  place-items: center;
  overflow: hidden;
  padding: 0.75rem;
}

.empty {
  color: var(--gg-muted);
  font-size: 0.875rem;
}

.grid {
  --gg-grid-cell-size: 1.45rem;
  --gg-grid-glyph-size: 0.98rem;
  display: grid;
  grid-auto-rows: var(--gg-grid-cell-size);
  gap: 2px;
  align-content: center;
  justify-content: center;
  inline-size: max-content;
  max-inline-size: 100%;
  max-block-size: 100%;
}

.row {
  display: contents;
}

.cell {
  position: relative;
  display: grid;
  width: var(--gg-grid-cell-size);
  height: var(--gg-grid-cell-size);
  place-items: center;
  overflow: hidden;
  border: 1px solid rgba(255, 255, 255, 0.035);
  border-radius: 4px;
  background: #111820;
  color: #aeb8c4;
  font-size: var(--gg-grid-glyph-size);
  line-height: 1;
  letter-spacing: 0;
  transition:
    background-color 50ms ease-out,
    border-color 50ms ease-out,
    color 50ms ease-out,
    opacity 50ms ease-out;
}

.glyph {
  position: relative;
  z-index: 1;
  font-weight: 700;
  text-shadow: 0 0 0.55rem currentColor;
}

.badge {
  position: absolute;
  z-index: 2;
  right: 1px;
  bottom: 1px;
  min-width: 0.78rem;
  padding: 0 1px;
