  letter-spacing: 0;
  text-align: center;
  text-transform: uppercase;
}

.shape::before {
  position: absolute;
  z-index: 0;
  top: 3px;
  left: 3px;
  width: 0.42rem;
  height: 0.42rem;
  border: 1px solid currentColor;
