  const wall = { x: 3, y: 1 };
  const visibleFog = updateFogMemory(
    createFogMemory(grid),
    grid,
    visibleCells(grid, origin, 2),
  );
  const changedGrid = withTile(grid, wall, createTile(Terrain.Floor));
  const rememberedFog = updateFogMemory(
    visibleFog,
    changedGrid,
