137	const hudPulsesSinceLastRender = (
138	  state: GameState,
139	  previousCursor?: HudRenderCursor,
140	): ReadonlySet<HudPulseTarget> => {
141	  const cursor = cursorForState(state);
142	  const canDiff =
143	    previousCursor !== undefined &&
144	    previousCursor.runId === cursor.runId &&
145	    previousCursor.floorId === cursor.floorId &&
146	    previousCursor.logLength <= cursor.logLength;
147	
148	  if (!canDiff) {
149	    return new Set();
150	  }
151	
152	  const pulses = new Set<HudPulseTarget>();
153	  const events = (state.log as readonly RuntimeLogEvent[]).slice(
154	    previousCursor.logLength,
155	  );
156	
157	  for (const event of events) {
158	    const hud = asRecord(asRecord(event.data)?.hud);
159	
160	    if (hud?.pulse !== true) {
161	      continue;
162	    }
163	
164	    const fields = arrayValue(hud.fields);
165	
166	    for (const field of fields) {
167	      if (typeof field !== "string") {
168	        continue;
169	      }
170	
171	      for (const target of pulseTargetsForField(field)) {
172	        pulses.add(target);
173	      }
174	    }
175	  }
176	
177	  return pulses;
178	};
179	
180	const pulseTargetsForField = (
181	  field: string,
182	): readonly HudPulseTarget[] => {
183	  switch (field) {
184	    case "depth":
185	      return ["depth"];
186	    case "turn":
187	      return ["turn"];
188	    case "hp":
189	    case "maxHp":
190	      return ["hp"];
191	    case "fullness":
192	      return ["fullness"];
193	    case "level":
194	    case "xp":
195	    case "attack":
196	    case "defense":
197	      return ["levelXp"];
198	    case "status":
199	    case "statuses":
200	      return ["statuses"];
201	    default:
202	      return [];
203	  }
204	};
205	
206	const labelForStatus = (status: string): string =>
207	  status
208	    .split("_")
209	    .filter((part) => part.length > 0)
210	    .map((part) => `${part.charAt(0).toUpperCase()}${part.slice(1)}`)
211	    .join(" ");
212	
213	const shapeForStatus = (status: string): StatusChipShape =>
214	  STATUS_SHAPES[status] ?? "square";
215	
216	const percent = (current: number, max: number): number => {
217	  if (max <= 0) {
218	    return 0;
219	  }
220	
221	  return clamp((current / max) * 100, 0, 100);
222	};
223	
224	const clamp = (value: number, min: number, max: number): number =>
225	  Math.min(max, Math.max(min, value));
226	
227	const asRecord = (value: unknown): RuntimeRecord | null =>
228	  value !== null && typeof value === "object"
229	    ? (value as RuntimeRecord)
230	    : null;
231	
232	const arrayValue = (value: unknown): readonly unknown[] =>
233	  Array.isArray(value) ? value : [];
